import React from 'react';

interface CouponCardProps {
  title: string;
  expiry: string;
  maxDiscount: number;
  discountRate: number;
  onUse: () => void;
}

const CouponCard: React.FC<CouponCardProps> = ({ title, expiry, maxDiscount, discountRate, onUse }) => {
  return (
    <div className="relative border rounded-lg flex flex-col gap-2 bg-gray-100 overflow-visible">
      <div className="flex flex-col justify-between items-center px-2">
        <div className="flex flex-col w-full py-3 px-2">
          <div className="font-semibold mb-1">{title}</div>
          <div className="text-xs text-gray-500">{expiry}</div>
          <div className="text-xs text-gray-400">(최대 {maxDiscount.toLocaleString()}원 할인)</div>
        </div>
        <div className="flex flex-row items-center justify-between w-full">
          <div className="text-orange-600 font-bold text-sm">사용 가능</div>
          <div className="text-blue-600 font-bold text-sm">{discountRate}%</div>
        </div>
      </div>

      {/* 쿠폰 하단 마스킹 효과: 진짜 구멍이 뚫린 것처럼 보이게 */}
      <div className="relative h-6 mb-1">
        <div className="absolute inset-0 bg-whit rounded-lg z-0"></div>
        <div className="coupon-mask absolute inset-0 pointer-events-none z-10"></div>
        <div className="absolute left-3 right-3 top-1/2 border-b-2 border-dashed border-gray-300 z-20"></div>
      </div>
      <button
        className="w-full bg-blue-600 text-white py-2 rounded-b-lg font-semibold hover:bg-blue-700 transition"
        onClick={onUse}
      >
        COUPON
      </button>

    </div>
  );
};

export default CouponCard;
